/* ─── Image Upload ────────────────────────────────────────────── */
function ImageUpload({ value, onChange, size = 80 }) {
  const ref = useRef();
  const handleFile = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => onChange(ev.target.result);
    reader.readAsDataURL(file);
  };
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
      <div onClick={() => ref.current.click()} style={{
        width: size, height: size, borderRadius: "var(--border-radius-lg)",
        border: `2px dashed ${T.yellow}`, cursor: "pointer", overflow: "hidden",
        display: "flex", alignItems: "center", justifyContent: "center", background: T.bgSec, flexShrink: 0 }}>
        {value
          ? <img src={value} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
          : <div style={{ textAlign: "center", color: T.textSec }}><div style={{ fontSize: 22 }}>📸</div><div style={{ fontSize: 10, marginTop: 2 }}>Upload</div></div>
        }
      </div>
      <div>
        <Btn size="sm" variant="ghost" onClick={() => ref.current.click()}>📸 Choose Photo</Btn>
        {value && <Btn size="sm" variant="danger" onClick={() => onChange("")} style={{ marginLeft: 6 }}>Remove</Btn>}
        <div style={{ fontSize: 11, color: T.textSec, marginTop: 4 }}>Appears on menu card</div>
      </div>
      <input ref={ref} type="file" accept="image/*" onChange={handleFile} style={{ display: "none" }} />
    </div>
  );
}

function ProductThumb({ product, size = 52 }) {
  if (product.image) return <img src={product.image} alt={product.name} style={{ width: size, height: size, objectFit: "cover", borderRadius: "var(--border-radius-md)", flexShrink: 0 }} />;
  return (
    <div style={{ width: size, height: size, borderRadius: "var(--border-radius-md)", background: `linear-gradient(135deg, ${T.yellow}30, ${T.warm})`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: size * 0.45, flexShrink: 0, border: `1px solid ${T.border}` }}>
      {categoryEmoji(product.category || "")}
    </div>
  );
}

/* ─── Receipt Print ───────────────────────────────────────────── */
function printBill(sale, settings) {
  const W = 32;
  const NL = "\n";
  const line = "-".repeat(W);
  const dline = "=".repeat(W);

  const center = (txt) => {
    txt = String(txt);
    if (txt.length >= W) return txt;
    const pad = Math.floor((W - txt.length) / 2);
    return " ".repeat(pad) + txt;
  };

  const lr = (left, right) => {
    left = String(left); right = String(right);
    const space = Math.max(1, W - left.length - right.length);
    return left + " ".repeat(space) + right;
  };

  const itemRow = (name, qty, price, total) => {
    const maxName = 16;
    const n = (name.length > maxName ? name.slice(0, maxName) : name).padEnd(maxName);
    const q = ("x" + qty).padStart(3);
    const p = String(price).padStart(5);
    const t = String(total).padStart(6);
    return n + q + p + t;
  };

  const lines = [];
  lines.push("");
  lines.push(center(settings.shopName));
  lines.push(center(settings.shopAddress));
  lines.push(center("Tel: " + settings.shopPhone));
  lines.push(dline);
  lines.push("Receipt #" + String(sale.id).slice(-6));
  lines.push(" " + (sale.date || "") + (sale.time ? " " + sale.time : ""));
  lines.push(dline);
  lines.push("Item            Qty  Price Total");
  lines.push(line);

  (sale.items || []).forEach(i => {
    lines.push(itemRow(i.name, i.qty, i.price, i.price * i.qty));
  });

  lines.push(line);

  if (sale.subtotal && sale.discount > 0) {
    lines.push(lr("Subtotal", "TK " + sale.subtotal));
    lines.push(lr("Discount(" + (sale.discountLabel || "") + ")", "-TK " + sale.discount));
    lines.push(line);
  }

  lines.push(lr("TOTAL",  "TK " + sale.total));
  lines.push(lr("Paid",   "TK " + (sale.paid || sale.total)));
  lines.push(lr("Change", "TK " + (sale.change || 0)));
  lines.push(dline);
  lines.push(center(settings.shopTagline));
  lines.push(center("Thank you for dining with us!"));
  lines.push("");
  lines.push("");
  lines.push("");

  const txt = lines.join(NL);

  if (window.electronAPI) {
    window.electronAPI.printReceipt(txt);
  } else {
    const blob = new Blob([txt], { type: "text/plain;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "receipt-" + String(sale.id).slice(-6) + ".txt";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }
}

/* ─── Login ───────────────────────────────────────────────────── */
function Login({ users, onLogin }) {
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [showPw, setShowPw] = useState(false);

  const attempt = () => {
    const u = users.find(u => u.username.toLowerCase() === username.toLowerCase() && u.password === password);
    if (u) onLogin(u); else { setError("Incorrect username or password"); setPassword(""); }
  };

  return (
    <div style={{ minHeight: "100vh", display: "flex", background: T.dark }}>
      {/* Left panel - brand */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
        background: `linear-gradient(135deg, ${T.dark} 0%, #3d1400 100%)`, padding: "3rem", position: "relative", overflow: "hidden" }}>
        {/* Decorative circles */}
        {[...Array(3)].map((_, i) => (
          <div key={i} style={{ position: "absolute", borderRadius: "50%", border: `1px solid ${T.yellow}20`,
            width: 200 + i * 180, height: 200 + i * 180, top: "50%", left: "50%",
            transform: "translate(-50%, -50%)", pointerEvents: "none" }} />
        ))}
        <img src={LOGO} alt="Mady" style={{ width: 180, height: 180, objectFit: "cover", borderRadius: 24, marginBottom: "1.5rem", boxShadow: `0 0 60px ${T.yellow}40`, position: "relative" }} />
        <h1 style={{ color: T.yellow, fontSize: 52, fontWeight: 900, margin: "0 0 8px", letterSpacing: "-2px", position: "relative" }}>Mady</h1>
        <p style={{ color: `${T.yellow}90`, fontSize: 16, fontStyle: "italic", position: "relative" }}>beware you will go mad.</p>
        <p style={{ color: `${T.yellow}60`, fontSize: 13, marginTop: 8, position: "relative" }}>📍 Concord Moin Square, Chattogram</p>
      </div>

      {/* Right panel - login */}
      <div style={{ width: 420, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
        background: T.warm, padding: "3rem" }}>
        <div style={{ width: "100%", maxWidth: 340 }}>
          <h2 style={{ fontSize: 22, fontWeight: 800, color: T.dark, marginBottom: 4 }}>Staff Login</h2>
          <p style={{ fontSize: 14, color: T.textSec, marginBottom: "2rem" }}>Sign in to access the POS system</p>

          <Field label="Username">
            <input value={username} onChange={e => { setUsername(e.target.value); setError(""); }}
              placeholder="Enter username" onKeyDown={e => e.key === "Enter" && attempt()} autoFocus />
          </Field>
          <Field label="Password">
            <div style={{ position: "relative" }}>
              <input type={showPw ? "text" : "password"} value={password}
                onChange={e => { setPassword(e.target.value); setError(""); }}
                placeholder="Enter password" onKeyDown={e => e.key === "Enter" && attempt()} style={{ paddingRight: 44 }} />
              <button onClick={() => setShowPw(p => !p)} style={{ position: "absolute", right: 10, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", fontSize: 17, color: T.textSec }}>
                {showPw ? "🙈" : "👁"}
              </button>
            </div>
          </Field>

          {error && <div style={{ fontSize: 13, color: T.dangerTxt, background: T.danger, padding: "9px 12px", borderRadius: "var(--border-radius-md)", marginBottom: "1rem", display: "flex", alignItems: "center", gap: 6 }}>⚠ {error}</div>}

          <Btn variant="primary" size="xl" onClick={attempt} fullWidth>Sign in →</Btn>
          <p style={{ fontSize: 12, color: T.textSec, textAlign: "center", marginTop: "1.5rem" }}>
            Mady POS v2.0 · Powered by React
          </p>
        </div>
      </div>

      <style>{`
        input { background: #fff; color: ${T.dark}; border: 1.5px solid ${T.borderSec}; border-radius: var(--border-radius-md); padding: 10px 14px; font-size: 14px; outline: none; width: 100%; font-family: var(--font-sans); transition: border-color 0.15s, box-shadow 0.15s; }
        input:focus { border-color: ${T.yellow}; box-shadow: 0 0 0 3px ${T.yellow}25; }
      `}</style>
    </div>
  );
}

