/* ─── Dashboard ───────────────────────────────────────────────── */
function Dashboard({ products, sales, setPage }) {
  const totalValue = products.reduce((s, p) => s + p.price * p.quantity, 0);
  const totalRev   = sales.reduce((s, x) => s + x.total, 0);
  const lowStock   = products.filter(p => p.quantity < 10);
  const today      = now();
  const todaySales = sales.filter(s => s.date === today).reduce((s, x) => s + x.total, 0);
  const todayOrders= sales.filter(s => s.date === today).length;
  const topItems   = products.slice().sort((a,b) => b.price - a.price).slice(0, 3);

  return (
    <div>
      <PageHeader title="Good day! 👋" sub={`Restaurant overview · ${today}`} />

      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 14, marginBottom: "2rem" }}>
        <StatCard label="Menu Value"      value={fmt(totalValue)} sub={`${products.length} items on menu`} icon="🍽️" />
        <StatCard label="Total Revenue"   value={fmt(totalRev)} sub={`${sales.length} total orders`} icon="💰" />
        <StatCard label="Today's Revenue" value={fmt(todaySales)} sub={`${todayOrders} orders today`} icon="📈" color={T.red} />
        <StatCard label="Low Stock"       value={lowStock.length} sub="items need restocking" icon="⚠️" color={lowStock.length > 0 ? T.dangerTxt : T.successTxt} />
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 16, marginBottom: 16 }}>
        <Card>
          <CardHead title="🍽️ Menu Items" sub="Current stock levels" right={<Btn size="sm" variant="ghost" onClick={() => setPage("inventory")}>Manage menu →</Btn>} accent />
          <table className="data-table">
            <thead><tr><th></th><th>Item</th><th>Category</th><th>Price</th><th>Stock</th></tr></thead>
            <tbody>
              {products.slice(0, 7).map(p => (
                <tr key={p.id}>
                  <td style={{ width: 44, paddingRight: 4 }}><ProductThumb product={p} size={34} /></td>
                  <td style={{ fontWeight: 600 }}>{p.name}</td>
                  <td><Badge label={p.category || "—"} bg={`${T.yellow}25`} color={T.dark} /></td>
                  <td style={{ fontWeight: 700, color: T.red }}>{fmt(p.price)}</td>
                  <td><Badge label={p.quantity} bg={p.quantity < 10 ? T.danger : p.quantity < 30 ? T.warning : T.success} color={p.quantity < 10 ? T.dangerTxt : p.quantity < 30 ? T.warningTxt : T.successTxt} /></td>
                </tr>
              ))}
            </tbody>
          </table>
        </Card>

        <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
          <Card>
            <CardHead title="🔥 Top Priced" accent />
            <div style={{ padding: "0.75rem" }}>
              {topItems.map((p, i) => (
                <div key={p.id} style={{ display: "flex", alignItems: "center", gap: 10, padding: "8px 6px", borderBottom: i < topItems.length - 1 ? `1px solid ${T.border}` : "none" }}>
                  <div style={{ width: 26, height: 26, borderRadius: "50%", background: [T.yellow, `${T.yellow}80`, `${T.yellow}40`][i], display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, fontWeight: 800, color: T.dark, flexShrink: 0 }}>{i+1}</div>
                  <ProductThumb product={p} size={30} />
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 13, fontWeight: 600 }}>{p.name}</div>
                    <div style={{ fontSize: 11, color: T.textSec }}>{fmt(p.price)}</div>
                  </div>
                </div>
              ))}
            </div>
          </Card>

          <Card>
            <CardHead title="📋 Recent Orders" accent />
            <div style={{ padding: "0.5rem 0" }}>
              {[...sales].reverse().slice(0, 4).map(s => (
                <div key={s.id} style={{ display: "flex", justifyContent: "space-between", padding: "7px 14px", borderBottom: `1px solid ${T.border}`, fontSize: 13 }}>
                  <span style={{ color: T.textSec }}>{s.date}</span>
                  <span style={{ fontWeight: 700, color: T.red }}>{fmt(s.total)}</span>
                </div>
              ))}
              {sales.length === 0 && <div style={{ padding: "1.5rem", textAlign: "center", color: T.textSec, fontSize: 13 }}>No orders yet</div>}
            </div>
          </Card>
        </div>
      </div>

      {lowStock.length > 0 && (
        <Card style={{ border: `1px solid ${T.yellow}50` }}>
          <CardHead title="⚠️ Restock Alert" sub="These items are running low" accent />
          <div style={{ padding: "1rem 1.25rem", display: "flex", flexWrap: "wrap", gap: 8 }}>
            {lowStock.map(p => (
              <div key={p.id} style={{ background: T.danger, color: T.dangerTxt, padding: "6px 14px", borderRadius: "999px", fontSize: 13, fontWeight: 600 }}>
                {p.name} · {p.quantity} left
              </div>
            ))}
          </div>
        </Card>
      )}
    </div>
  );
}

/* ─── POS ─────────────────────────────────────────────────────── */
function POS({ products, setProducts, sales, setSales, showToast, settings }) {
  const [cart,      setCart]     = useState([]);
  const [search,    setSearch]   = useState("");
  const [category,  setCategory] = useState("All");
  const [paid,      setPaid]     = useState("");
  const [discount,  setDiscount] = useState("");
  const [discountType, setDiscountType] = useState("flat"); // "flat" or "percent"
  const [receipt,   setReceipt]  = useState(null);
  const [note,      setNote]     = useState("");
  const searchRef = useRef();

  const addToCart = (p) => {
    if (p.quantity < 1) { showToast("Out of stock!", "danger"); return; }
    setCart(prev => {
      const ex = prev.find(i => i.id === p.id);
      if (ex) return prev.map(i => i.id === p.id ? { ...i, qty: Math.min(i.qty + 1, p.quantity) } : i);
      return [...prev, { ...p, qty: 1 }];
    });
  };

  const updateQty = (id, qty) => {
    if (qty < 1) setCart(p => p.filter(i => i.id !== id));
    else setCart(p => p.map(i => i.id === id ? { ...i, qty } : i));
  };

  const subtotal     = cart.reduce((s, i) => s + i.price * i.qty, 0);
  const discountAmt  = discountType === "percent"
    ? Math.round(subtotal * (parseFloat(discount) || 0) / 100)
    : Math.round(parseFloat(discount) || 0);
  const total        = Math.max(0, subtotal - discountAmt);
  const paidAmt      = parseFloat(paid) || 0;
  const change       = Math.max(0, paidAmt - total);

  const checkout = () => {
    if (!cart.length) return;
    if (paidAmt < total) { showToast("Amount paid is less than total", "danger"); return; }
    setProducts(prev => prev.map(p => { const ci = cart.find(i => i.id === p.id); return ci ? { ...p, quantity: p.quantity - ci.qty } : p; }));
    const sale = { id: Date.now(), total, subtotal, discount: discountAmt, discountLabel: discount && discountAmt > 0 ? (discountType === "percent" ? discount+"%" : "৳"+discount) : null, date: now(), time: time(), note,
      items: cart.map(i => ({ id: i.id, name: i.name, qty: i.qty, price: i.price })), paid: paidAmt, change };
    setDiscount("");
    setSales(prev => [...prev, sale]);
    setReceipt(sale); setCart([]); setPaid(""); setNote("");
    showToast(`Order complete! Change: ${fmt(change)} 🎉`);
  };

  const cats = ["All", ...new Set(products.map(p => p.category).filter(Boolean))];
  const filtered = products.filter(p =>
    (category === "All" || p.category === category) &&
    p.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div>
      <PageHeader title="🍔 New Order" sub="Select items and complete the order" />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 400px", gap: 18, alignItems: "start" }}>

        {/* Left: Menu */}
        <div>
          {/* Search + Categories */}
          <div style={{ marginBottom: 14 }}>
            <input ref={searchRef} value={search} onChange={e => setSearch(e.target.value)}
              placeholder="🔍  Search menu items…" autoFocus style={{ marginBottom: 10 }} />
            <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
              {cats.map(cat => (
                <button key={cat} onClick={() => setCategory(cat)} style={{
                  padding: "5px 14px", borderRadius: "999px", border: `1.5px solid ${category === cat ? T.yellow : T.borderSec}`,
                  background: category === cat ? T.yellow : "transparent", color: category === cat ? T.dark : T.textSec,
                  cursor: "pointer", fontSize: 12, fontWeight: 600, fontFamily: "var(--font-sans)", transition: "all 0.1s" }}>
                  {cat === "All" ? "🍽️ All" : `${categoryEmoji(cat)} ${cat}`}
                </button>
              ))}
            </div>
          </div>

          {/* Product Grid */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(155px, 1fr))", gap: 12 }}>
            {filtered.map(p => (
              <button key={p.id} onClick={() => addToCart(p)} disabled={p.quantity === 0}
                onMouseEnter={e => p.quantity > 0 && (e.currentTarget.style.transform = "translateY(-2px)", e.currentTarget.style.boxShadow = "var(--shadow-md)")}
                onMouseLeave={e => (e.currentTarget.style.transform = "translateY(0)", e.currentTarget.style.boxShadow = "var(--shadow-sm)")}
                style={{ background: T.bg, border: `1px solid ${p.quantity === 0 ? T.border : T.borderSec}`,
                  borderRadius: "var(--border-radius-lg)", padding: 0, cursor: p.quantity === 0 ? "not-allowed" : "pointer",
                  textAlign: "left", opacity: p.quantity === 0 ? 0.5 : 1, transition: "all 0.15s",
                  fontFamily: "var(--font-sans)", overflow: "hidden", boxShadow: "var(--shadow-sm)" }}>
                <div style={{ width: "100%", height: 100, background: `linear-gradient(135deg, ${T.yellow}20, ${T.warm})`, overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center", position: "relative" }}>
                  {p.image
                    ? <img src={p.image} alt={p.name} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                    : <span style={{ fontSize: 42 }}>{categoryEmoji(p.category || "")}</span>
                  }
                  {p.category && <span style={{ position: "absolute", top: 6, right: 6, background: T.yellow, color: T.dark, fontSize: 9, fontWeight: 700, padding: "2px 6px", borderRadius: "999px" }}>{p.category}</span>}
                </div>
                <div style={{ padding: "10px 12px" }}>
                  <div style={{ fontWeight: 700, fontSize: 13, color: T.text, marginBottom: 4, lineHeight: 1.3 }}>{p.name}</div>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                    <span style={{ fontSize: 16, fontWeight: 800, color: T.red }}>{fmt(p.price)}</span>
                    <span style={{ fontSize: 10, color: p.quantity < 10 ? T.dangerTxt : T.textSec }}>{p.quantity === 0 ? "Sold out" : `${p.quantity} left`}</span>
                  </div>
                </div>
              </button>
            ))}
            {filtered.length === 0 && <div style={{ gridColumn: "1/-1", padding: "3rem", textAlign: "center", color: T.textSec, fontSize: 14 }}>No items found</div>}
          </div>
        </div>

        {/* Right: Order */}
        <div style={{ position: "sticky", top: 0 }}>
          <Card style={{ border: `1px solid ${T.borderSec}` }}>
            <CardHead title="🧾 Current Order" sub={`${cart.length} item${cart.length !== 1 ? "s" : ""}`}
              right={cart.length > 0 && <Btn size="xs" variant="danger" onClick={() => setCart([])}>Clear</Btn>} accent />

            <div style={{ minHeight: 160, maxHeight: 340, overflow: "auto" }}>
              {cart.length === 0 && (
                <div style={{ padding: "2.5rem 1rem", textAlign: "center", color: T.textSec }}>
                  <div style={{ fontSize: 40, marginBottom: 8 }}>🍔</div>
                  <div style={{ fontSize: 14, fontWeight: 500 }}>Tap a menu item to add</div>
                </div>
              )}
              {cart.map(item => (
                <div key={item.id} style={{ padding: "10px 14px", display: "flex", alignItems: "center", gap: 10, borderBottom: `1px solid ${T.border}` }}>
                  <ProductThumb product={item} size={36} />
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 700, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{item.name}</div>
                    <div style={{ fontSize: 12, color: T.textSec }}>{fmt(item.price)} × {item.qty} = <strong style={{ color: T.red }}>{fmt(item.price * item.qty)}</strong></div>
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 3 }}>
                    <Btn size="xs" onClick={() => updateQty(item.id, item.qty - 1)}>−</Btn>
                    <span style={{ minWidth: 22, textAlign: "center", fontSize: 14, fontWeight: 800 }}>{item.qty}</span>
                    <Btn size="xs" onClick={() => updateQty(item.id, item.qty + 1)}>+</Btn>
                  </div>
                </div>
              ))}
            </div>

            <div style={{ padding: "1rem 1.25rem", borderTop: `1px solid ${T.border}`, background: `${T.warm}` }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4, fontSize: 13, color: T.textSec }}>
                <span>Subtotal</span><span>{fmt(subtotal)}</span>
              </div>
              {/* Discount Row */}
              <div style={{ marginBottom: 8 }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: T.textSec, textTransform: "uppercase", letterSpacing: "0.05em", marginBottom: 4 }}>Discount</div>
                <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
                  <input
                    type="number"
                    value={discount}
                    onChange={e => setDiscount(e.target.value)}
                    placeholder={discountType === "percent" ? "e.g. 10" : "e.g. 50"}
                    min={0}
                    style={{ flex: 1 }}
                  />
                  <div style={{ display: "flex", borderRadius: "var(--border-radius-md)", overflow: "hidden", border: `1px solid ${T.borderSec}`, flexShrink: 0 }}>
                    <button onClick={() => setDiscountType("flat")} style={{
                      padding: "7px 10px", fontSize: 12, fontWeight: 700, border: "none", cursor: "pointer",
                      background: discountType === "flat" ? T.yellow : "transparent",
                      color: discountType === "flat" ? T.dark : T.textSec,
                      fontFamily: "var(--font-sans)"
                    }}>৳</button>
                    <button onClick={() => setDiscountType("percent")} style={{
                      padding: "7px 10px", fontSize: 12, fontWeight: 700, border: "none", cursor: "pointer",
                      background: discountType === "percent" ? T.yellow : "transparent",
                      color: discountType === "percent" ? T.dark : T.textSec,
                      fontFamily: "var(--font-sans)"
                    }}>%</button>
                  </div>
                </div>
                {discountAmt > 0 && (
                  <div style={{ fontSize: 12, color: T.successTxt, marginTop: 3, fontWeight: 600 }}>
                    − {fmt(discountAmt)} off
                  </div>
                )}
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", padding: "8px 0", borderTop: `2px solid ${T.yellow}40` }}>
                <span style={{ fontSize: 17, fontWeight: 800 }}>Total</span>
                <span style={{ fontSize: 26, fontWeight: 900, color: T.red, letterSpacing: "-0.5px" }}>{fmt(total)}</span>
              </div>

              <Field label="Paid Amount (৳)">
                <input type="number" value={paid} onChange={e => setPaid(e.target.value)}
                  placeholder={total > 0 ? `Min. ${fmt(total)}` : "0"} min={0} />
              </Field>

              {paid && (
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.75rem",
                  background: paidAmt >= total ? "#d1fae5" : T.danger, padding: "9px 14px",
                  borderRadius: "var(--border-radius-md)", border: `1px solid ${paidAmt >= total ? "#a7f3d0" : "#fca5a5"}` }}>
                  <span style={{ fontWeight: 700, color: paidAmt >= total ? "#065f46" : T.dangerTxt }}>
                    {paidAmt >= total ? "Change" : "Short by"}
                  </span>
                  <span style={{ fontWeight: 800, fontSize: 16, color: paidAmt >= total ? "#065f46" : T.dangerTxt }}>
                    {paidAmt >= total ? fmt(change) : fmt(total - paidAmt)}
                  </span>
                </div>
              )}

              <Btn variant="success" size="lg" onClick={checkout} disabled={!cart.length || paidAmt < total} fullWidth>
                ✓ Complete Order
              </Btn>
            </div>
          </Card>
        </div>
      </div>

      {/* Receipt Modal */}
      {receipt && (
        <Modal title="✅ Order Complete!" onClose={() => setReceipt(null)}>
          <div style={{ background: T.bgSec, borderRadius: "var(--border-radius-lg)", padding: "1.25rem", marginBottom: "1rem", fontFamily: "var(--font-mono)", fontSize: 13 }}>
            <div style={{ textAlign: "center", marginBottom: "1rem" }}>
              <img src={LOGO} alt="Mady" style={{ width: 64, height: 64, objectFit: "cover", borderRadius: "var(--border-radius-md)", marginBottom: 6 }} />
              <div style={{ fontWeight: 900, fontSize: 18 }}>{settings.shopName}</div>
              <div style={{ fontSize: 12, color: T.textSec }}>{settings.shopAddress}</div>
            </div>
            <Divider />
            {receipt.items.map((i, idx) => (
              <div key={idx} style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                <span>{i.name} ×{i.qty}</span><span style={{ fontWeight: 600 }}>{fmt(i.price * i.qty)}</span>
              </div>
            ))}
            <Divider />
            <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 800, fontSize: 16, marginBottom: 4 }}>
              <span>TOTAL</span><span style={{ color: T.red }}>{fmt(receipt.total)}</span>
            </div>
            <div style={{ display: "flex", justifyContent: "space-between", color: T.textSec, fontSize: 12 }}><span>Paid</span><span>{fmt(receipt.paid)}</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", color: T.textSec, fontSize: 12 }}><span>Change</span><span>{fmt(receipt.change)}</span></div>
            <Divider />
            <div style={{ textAlign: "center", fontSize: 12, color: T.textSec, fontStyle: "italic" }}>{settings.shopTagline}</div>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <Btn onClick={() => setReceipt(null)} style={{ flex: 1, justifyContent: "center" }}>Close</Btn>
            <Btn variant="primary" onClick={() => printBill(receipt, settings)} style={{ flex: 1, justifyContent: "center" }}>🖨️ Print Receipt</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
}

/* ─── Menu/Inventory ──────────────────────────────────────────── */
function Inventory({ products, setProducts, showToast }) {
  const [search, setSearch] = useState("");
  const [modal,  setModal]  = useState(null);
  const [form,   setForm]   = useState({ name: "", price: "", quantity: "", category: "", image: "" });

  const openAdd  = () => { setForm({ name: "", price: "", quantity: "", category: "Burgers", image: "" }); setModal("add"); };
  const openEdit = p  => { setForm({ name: p.name, price: p.price, quantity: p.quantity, category: p.category || "", image: p.image || "" }); setModal(p.id); };
  const save = () => {
    if (!form.name.trim() || form.price === "" || form.quantity === "") { showToast("Fill all required fields", "danger"); return; }
    if (modal === "add") {
      setProducts(prev => [...prev, { id: Date.now(), name: form.name.trim().toUpperCase(), price: +form.price, quantity: +form.quantity, category: form.category, image: form.image }]);
      showToast("Menu item added 🍔");
    } else {
      setProducts(prev => prev.map(p => p.id === modal ? { ...p, name: form.name.trim().toUpperCase(), price: +form.price, quantity: +form.quantity, category: form.category, image: form.image } : p));
      showToast("Menu item updated");
    }
    setModal(null);
  };
  const del = id => {
    if (!window.confirm("Remove this item from the menu?")) return;
    setProducts(prev => prev.filter(p => p.id !== id));
    showToast("Item removed", "danger");
  };

  const filtered   = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));
  const totalValue = products.reduce((s, p) => s + p.price * p.quantity, 0);

  return (
    <div>
      <PageHeader title="🍽️ Menu Items" sub={`${products.length} items · Stock value: ${fmt(totalValue)}`}
        action={<Btn variant="primary" size="lg" onClick={openAdd}>+ Add Item</Btn>} />
      <Card>
        <CardHead title="All Menu Items" accent
          right={<input value={search} onChange={e => setSearch(e.target.value)} placeholder="🔍 Search menu…" style={{ width: 240 }} />} />
        <table className="data-table">
          <thead><tr><th style={{ width: 50 }}></th><th>Name</th><th>Category</th><th>Price</th><th>Qty</th><th>Status</th><th style={{ width: 110 }}>Actions</th></tr></thead>
          <tbody>
            {filtered.map(p => (
              <tr key={p.id}>
                <td style={{ paddingRight: 4 }}><ProductThumb product={p} size={38} /></td>
                <td style={{ fontWeight: 700 }}>{p.name}</td>
                <td><Badge label={p.category || "—"} bg={`${T.yellow}25`} color={T.dark} /></td>
                <td style={{ fontWeight: 800, color: T.red }}>{fmt(p.price)}</td>
                <td style={{ fontWeight: 600 }}>{p.quantity}</td>
                <td>
                  <Badge label={p.quantity === 0 ? "Sold out" : p.quantity < 10 ? "Low stock" : "Available"}
                    bg={p.quantity === 0 ? T.danger : p.quantity < 10 ? T.warning : T.success}
                    color={p.quantity === 0 ? T.dangerTxt : p.quantity < 10 ? T.warningTxt : T.successTxt} />
                </td>
                <td><div style={{ display: "flex", gap: 5 }}><Btn size="sm" variant="ghost" onClick={() => openEdit(p)}>✎ Edit</Btn><Btn size="sm" variant="danger" onClick={() => del(p.id)}>✕</Btn></div></td>
              </tr>
            ))}
            {filtered.length === 0 && <tr><td colSpan={7} style={{ textAlign: "center", padding: "3rem", color: T.textSec }}>No items found</td></tr>}
          </tbody>
        </table>
      </Card>

      {modal && (
        <Modal title={modal === "add" ? "➕ Add Menu Item" : "✎ Edit Menu Item"} onClose={() => setModal(null)}>
          <Field label="Photo"><ImageUpload value={form.image} onChange={v => setForm(f => ({ ...f, image: v }))} size={90} /></Field>
          <Field label="Item Name *"><input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="e.g. BEEF BURGER" /></Field>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12 }}>
            <Field label="Price (৳) *"><input type="number" value={form.price} onChange={e => setForm(f => ({ ...f, price: e.target.value }))} placeholder="0" min={0} /></Field>
            <Field label="Quantity *"><input type="number" value={form.quantity} onChange={e => setForm(f => ({ ...f, quantity: e.target.value }))} placeholder="0" min={0} /></Field>
            <Field label="Category">
              <select value={form.category} onChange={e => setForm(f => ({ ...f, category: e.target.value }))}>
                {CATEGORIES.filter(c => c !== "All").map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </Field>
          </div>
          <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: "1.5rem" }}>
            <Btn onClick={() => setModal(null)}>Cancel</Btn>
            <Btn variant="primary" onClick={save}>Save Item</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
}

/* ─── Order History ───────────────────────────────────────────── */
function History({ sales, setSales, settings, showToast }) {
  const [search,   setSearch]   = useState("");
  const [viewSale, setViewSale] = useState(null);
  const [confirmDel, setConfirmDel] = useState(null);
  const filtered     = [...sales].reverse().filter(s =>
    s.date.includes(search) || String(s.total).includes(search) ||
    (s.items || []).some(i => i.name.toLowerCase().includes(search.toLowerCase()))
  );
  const totalRevenue = sales.reduce((s, x) => s + x.total, 0);

  const deleteOrder = (id) => {
    setSales(prev => prev.filter(s => s.id !== id));
    showToast("Order deleted", "danger");
    setConfirmDel(null);
    if (viewSale?.id === id) setViewSale(null);
  };

  const clearAll = () => {
    if (!window.confirm("Delete ALL order history? This cannot be undone.")) return;
    setSales([]);
    showToast("All orders cleared", "danger");
  };

  return (
    <div>
      <PageHeader title="📋 Order History" sub={`${sales.length} orders · Revenue: ${fmt(totalRevenue)}`}
        action={sales.length > 0 && <Btn variant="danger" size="lg" onClick={clearAll}>🗑 Clear All</Btn>} />
      <Card>
        <CardHead title="All Orders" accent
          right={<input value={search} onChange={e => setSearch(e.target.value)} placeholder="🔍 Search orders…" style={{ width: 260 }} />} />
        <table className="data-table">
          <thead><tr><th>Order #</th><th>Date</th><th>Time</th><th>Items</th><th>Paid</th><th>Total</th><th>Actions</th></tr></thead>
          <tbody>
            {filtered.map(s => (
              <tr key={s.id}>
                <td style={{ fontFamily: "var(--font-mono)", fontSize: 12, color: T.textSec, fontWeight: 700 }}>#{String(s.id).slice(-6)}</td>
                <td>{s.date}</td>
                <td style={{ color: T.textSec }}>{s.time || "—"}</td>
                <td style={{ color: T.textSec, fontSize: 13 }}>{s.items?.length ? s.items.map(i => `${i.name} ×${i.qty}`).join(", ") : "—"}</td>
                <td style={{ color: T.textSec }}>{fmt(s.paid || s.total)}</td>
                <td style={{ fontWeight: 800, color: T.red }}>{fmt(s.total)}</td>
                <td><div style={{ display: "flex", gap: 5 }}>
                  <Btn size="sm" variant="ghost" onClick={() => setViewSale(s)}>👁 View</Btn>
                  <Btn size="sm" variant="primary" onClick={() => printBill(s, settings)}>🖨️</Btn>
                  <Btn size="sm" variant="danger" onClick={() => setConfirmDel(s)}>🗑</Btn>
                </div></td>
              </tr>
            ))}
            {filtered.length === 0 && <tr><td colSpan={7} style={{ textAlign: "center", padding: "3rem", color: T.textSec }}>No orders found</td></tr>}
          </tbody>
        </table>
      </Card>

      {/* Confirm Delete Modal */}
      {confirmDel && (
        <Modal title="🗑 Delete Order?" onClose={() => setConfirmDel(null)}>
          <p style={{ color: T.textSec, marginBottom: "1.25rem" }}>
            Are you sure you want to delete order <strong>#{String(confirmDel.id).slice(-6)}</strong> ({fmt(confirmDel.total)})? This cannot be undone.
          </p>
          <div style={{ display: "flex", gap: 8 }}>
            <Btn onClick={() => setConfirmDel(null)} style={{ flex: 1, justifyContent: "center" }}>Cancel</Btn>
            <Btn variant="danger" onClick={() => deleteOrder(confirmDel.id)} style={{ flex: 1, justifyContent: "center" }}>Yes, Delete</Btn>
          </div>
        </Modal>
      )}

      {viewSale && (
        <Modal title={`Order #${String(viewSale.id).slice(-6)}`} onClose={() => setViewSale(null)}>
          <div style={{ background: T.bgSec, borderRadius: "var(--border-radius-lg)", padding: "1.25rem", fontFamily: "var(--font-mono)", fontSize: 13, marginBottom: "1rem" }}>
            <div style={{ textAlign: "center", marginBottom: "1rem" }}>
              <img src={LOGO} alt="Mady" style={{ width: 55, height: 55, objectFit: "cover", borderRadius: "var(--border-radius-md)", marginBottom: 6 }} />
              <div style={{ fontWeight: 900, fontSize: 17 }}>{settings.shopName}</div>
              <div style={{ fontSize: 12, color: T.textSec }}>{viewSale.date} {viewSale.time || ""}</div>
            </div>
            <Divider />
            {(viewSale.items || []).map((i, idx) => (
              <div key={idx} style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                <span>{i.name} ×{i.qty}</span><span style={{ fontWeight: 600 }}>{fmt(i.price * i.qty)}</span>
              </div>
            ))}
            <Divider />
            <div style={{ display: "flex", justifyContent: "space-between", fontWeight: 800, fontSize: 16 }}><span>TOTAL</span><span style={{ color: T.red }}>{fmt(viewSale.total)}</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", color: T.textSec }}><span>Paid</span><span>{fmt(viewSale.paid || viewSale.total)}</span></div>
            <div style={{ display: "flex", justifyContent: "space-between", color: T.textSec }}><span>Change</span><span>{fmt(viewSale.change || 0)}</span></div>
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <Btn onClick={() => setViewSale(null)} style={{ flex: 1, justifyContent: "center" }}>Close</Btn>
            <Btn variant="primary" onClick={() => printBill(viewSale, settings)} style={{ flex: 1, justifyContent: "center" }}>🖨️ Print Receipt</Btn>
            <Btn variant="danger" onClick={() => { setConfirmDel(viewSale); setViewSale(null); }} style={{ flex: 1, justifyContent: "center" }}>🗑 Delete</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
}

/* ─── Daily Report ────────────────────────────────────────────── */
function DailyReport({ sales }) {
  const today = new Date().toLocaleDateString("en-GB");
  const [selectedDate, setSelectedDate] = useState(today);

  // Build list of all unique dates from sales
  const allDates = [...new Set(sales.map(s => s.date))].sort((a, b) => {
    const parse = d => { const [dd,mm,yyyy] = d.split("/"); return new Date(yyyy,mm-1,dd); };
    return parse(b) - parse(a);
  });

  const daySales = sales.filter(s => s.date === selectedDate);
  const totalRevenue = daySales.reduce((sum, s) => sum + s.total, 0);
  const totalOrders  = daySales.length;
  const avgOrder     = totalOrders ? totalRevenue / totalOrders : 0;

  // Item breakdown
  const itemMap = {};
  daySales.forEach(s => {
    (s.items || []).forEach(i => {
      if (!itemMap[i.name]) itemMap[i.name] = { qty: 0, revenue: 0 };
      itemMap[i.name].qty     += i.qty;
      itemMap[i.name].revenue += i.price * i.qty;
    });
  });
  const topItems = Object.entries(itemMap).sort((a, b) => b[1].revenue - a[1].revenue);

  // Hourly breakdown
  const hourMap = {};
  daySales.forEach(s => {
    const hour = s.time ? s.time.split(":")[0] + ":00" : "Unknown";
    if (!hourMap[hour]) hourMap[hour] = { orders: 0, revenue: 0 };
    hourMap[hour].orders++;
    hourMap[hour].revenue += s.total;
  });
  const hourly = Object.entries(hourMap).sort((a, b) => a[0].localeCompare(b[0]));

  // Compare to yesterday
  const parseDate = d => { const [dd,mm,yyyy] = (d||"").split("/"); return new Date(yyyy,mm-1,dd); };
  const selD = parseDate(selectedDate);
  const prevD = new Date(selD); prevD.setDate(prevD.getDate() - 1);
  const prevDate = prevD.toLocaleDateString("en-GB");
  const prevSales = sales.filter(s => s.date === prevDate);
  const prevRevenue = prevSales.reduce((sum, s) => sum + s.total, 0);
  const revDiff = prevRevenue ? ((totalRevenue - prevRevenue) / prevRevenue * 100) : null;

  const StatBox = ({ label, value, sub, color }) => (
    <div style={{ background: T.bgPri, border: `1.5px solid ${T.border}`, borderRadius: "var(--border-radius-lg)", padding: "1.25rem 1.5rem", flex: 1, minWidth: 160 }}>
      <div style={{ fontSize: 12, color: T.textSec, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 6 }}>{label}</div>
      <div style={{ fontSize: 26, fontWeight: 900, color: color || T.textPri }}>{value}</div>
      {sub && <div style={{ fontSize: 12, color: T.textSec, marginTop: 4 }}>{sub}</div>}
    </div>
  );

  return (
    <div>
      <PageHeader title="📈 Daily Report" sub="Track your daily sales performance" />

      {/* Date Selector */}
      <Card style={{ marginBottom: "1.25rem" }}>
        <CardHead title="Select Date" accent right={
          <select value={selectedDate} onChange={e => setSelectedDate(e.target.value)} style={{ width: "auto", minWidth: 180 }}>
            <option value={today}>Today ({today})</option>
            {allDates.filter(d => d !== today).map(d => <option key={d} value={d}>{d}</option>)}
            {allDates.length === 0 && <option value={today}>{today}</option>}
          </select>
        } />
        {daySales.length === 0 && (
          <div style={{ textAlign: "center", padding: "2rem", color: T.textSec }}>
            <div style={{ fontSize: 40, marginBottom: 8 }}>📭</div>
            <div style={{ fontWeight: 600 }}>No orders recorded on {selectedDate}</div>
          </div>
        )}
      </Card>

      {daySales.length > 0 && <>
        {/* KPI Stats */}
        <div style={{ display: "flex", gap: "1rem", marginBottom: "1.25rem", flexWrap: "wrap" }}>
          <StatBox label="Total Revenue" value={fmt(totalRevenue)} color={T.red}
            sub={revDiff !== null ? `${revDiff >= 0 ? "▲" : "▼"} ${Math.abs(revDiff).toFixed(1)}% vs prev day` : "No comparison data"} />
          <StatBox label="Total Orders" value={totalOrders} sub={`Avg ${fmt(avgOrder)} / order`} />
          <StatBox label="Best Hour" value={hourly.sort((a,b)=>b[1].revenue-a[1].revenue)[0]?.[0] || "—"}
            sub={hourly.sort((a,b)=>b[1].revenue-a[1].revenue)[0] ? fmt(hourly.sort((a,b)=>b[1].revenue-a[1].revenue)[0][1].revenue) : ""} />
          <StatBox label="Top Item" value={topItems[0]?.[0] || "—"}
            sub={topItems[0] ? `×${topItems[0][1].qty} sold · ${fmt(topItems[0][1].revenue)}` : ""} />
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "1.25rem", marginBottom: "1.25rem" }}>
          {/* Top Items Table */}
          <Card>
            <CardHead title="🏆 Item Performance" accent />
            <table className="data-table">
              <thead><tr><th>Item</th><th>Qty Sold</th><th>Revenue</th><th>Share</th></tr></thead>
              <tbody>
                {topItems.map(([name, d]) => (
                  <tr key={name}>
                    <td style={{ fontWeight: 600 }}>{name}</td>
                    <td style={{ color: T.textSec }}>×{d.qty}</td>
                    <td style={{ fontWeight: 700, color: T.red }}>{fmt(d.revenue)}</td>
                    <td>
                      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                        <div style={{ flex: 1, height: 6, background: T.bgSec, borderRadius: 3 }}>
                          <div style={{ width: `${(d.revenue / totalRevenue * 100).toFixed(0)}%`, height: "100%", background: T.red, borderRadius: 3 }} />
                        </div>
                        <span style={{ fontSize: 12, color: T.textSec, minWidth: 32 }}>{(d.revenue / totalRevenue * 100).toFixed(0)}%</span>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </Card>

          {/* Hourly Breakdown */}
          <Card>
            <CardHead title="⏰ Hourly Breakdown" accent />
            {hourly.length === 0
              ? <div style={{ textAlign: "center", padding: "2rem", color: T.textSec }}>No time data available</div>
              : <table className="data-table">
                <thead><tr><th>Hour</th><th>Orders</th><th>Revenue</th></tr></thead>
                <tbody>
                  {[...hourly].sort((a,b)=>a[0].localeCompare(b[0])).map(([hour, d]) => (
                    <tr key={hour}>
                      <td style={{ fontFamily: "var(--font-mono)", fontWeight: 600 }}>{hour}</td>
                      <td style={{ color: T.textSec }}>{d.orders} order{d.orders !== 1 ? "s" : ""}</td>
                      <td style={{ fontWeight: 700, color: T.red }}>{fmt(d.revenue)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            }
          </Card>
        </div>

        {/* Orders List */}
        <Card>
          <CardHead title={`📋 All Orders on ${selectedDate}`} accent />
          <table className="data-table">
            <thead><tr><th>Order #</th><th>Time</th><th>Items</th><th>Total</th></tr></thead>
            <tbody>
              {[...daySales].reverse().map(s => (
                <tr key={s.id}>
                  <td style={{ fontFamily: "var(--font-mono)", fontSize: 12, color: T.textSec, fontWeight: 700 }}>#{String(s.id).slice(-6)}</td>
                  <td style={{ color: T.textSec }}>{s.time || "—"}</td>
                  <td style={{ color: T.textSec, fontSize: 13 }}>{s.items?.map(i => `${i.name} ×${i.qty}`).join(", ") || "—"}</td>
                  <td style={{ fontWeight: 800, color: T.red }}>{fmt(s.total)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </Card>
      </>}
    </div>
  );
}


function Users({ users, setUsers, session, showToast }) {
  const [modal, setModal] = useState(null);
  const [form,  setForm]  = useState({ username: "", password: "", role: "Staff" });
  const openAdd  = () => { setForm({ username: "", password: "", role: "Staff" }); setModal("add"); };
  const openEdit = u  => { setForm({ username: u.username, password: u.password, role: u.role || "Staff" }); setModal(u.id); };
  const save = () => {
    if (!form.username.trim() || !form.password) { showToast("Fill all fields", "danger"); return; }
    if (modal === "add") {
      setUsers(prev => [...prev, { id: Date.now(), username: form.username.trim().toUpperCase(), password: form.password, role: form.role }]);
      showToast("Staff added");
    } else {
      setUsers(prev => prev.map(u => u.id === modal ? { ...u, username: form.username.trim().toUpperCase(), password: form.password, role: form.role } : u));
      showToast("Staff updated");
    }
    setModal(null);
  };
  const del = id => {
    if (id === session.id) { showToast("Cannot remove your own account", "danger"); return; }
    if (!window.confirm("Remove this staff member?")) return;
    setUsers(prev => prev.filter(u => u.id !== id));
    showToast("Staff removed", "danger");
  };

  return (
    <div>
      <PageHeader title="👨‍🍳 Staff" sub={`${users.length} staff members`} action={<Btn variant="primary" size="lg" onClick={openAdd}>+ Add Staff</Btn>} />
      <Card>
        <CardHead title="All Staff Members" accent />
        <table className="data-table">
          <thead><tr><th>Name</th><th>Role</th><th>Password</th><th style={{ width: 110 }}>Actions</th></tr></thead>
          <tbody>
            {users.map(u => (
              <tr key={u.id}>
                <td>
                  <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                    <div style={{ width: 34, height: 34, borderRadius: "50%", background: `linear-gradient(135deg, ${T.red}, #c0001a)`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14, fontWeight: 800, color: "#fff", flexShrink: 0 }}>{u.username[0]}</div>
                    <div>
                      <div style={{ fontWeight: 700 }}>{u.username}</div>
                      {u.id === session.id && <Badge label="You" bg={`${T.yellow}30`} color={T.dark} />}
                    </div>
                  </div>
                </td>
                <td><Badge label={u.role || "Staff"} bg={u.role === "Admin" ? `${T.red}20` : `${T.yellow}20`} color={u.role === "Admin" ? T.red : T.dark} /></td>
                <td style={{ color: T.textSec, fontFamily: "var(--font-mono)" }}>{"•".repeat(Math.min((u.password||"").length, 10))}</td>
                <td><div style={{ display: "flex", gap: 5 }}><Btn size="sm" variant="ghost" onClick={() => openEdit(u)}>✎ Edit</Btn><Btn size="sm" variant="danger" onClick={() => del(u.id)}>✕</Btn></div></td>
              </tr>
            ))}
          </tbody>
        </table>
      </Card>
      {modal && (
        <Modal title={modal === "add" ? "➕ Add Staff" : "✎ Edit Staff"} onClose={() => setModal(null)}>
          <Field label="Name"><input value={form.username} onChange={e => setForm(f => ({ ...f, username: e.target.value }))} placeholder="e.g. KARIM" autoFocus /></Field>
          <Field label="Password"><input value={form.password} onChange={e => setForm(f => ({ ...f, password: e.target.value }))} placeholder="Enter password" /></Field>
          <Field label="Role">
            <select value={form.role} onChange={e => setForm(f => ({ ...f, role: e.target.value }))}>
              <option value="Admin">Admin</option>
              <option value="Manager">Manager</option>
              <option value="Staff">Staff</option>
              <option value="Cashier">Cashier</option>
            </select>
          </Field>
          <div style={{ display: "flex", gap: 8, justifyContent: "flex-end", marginTop: "1.5rem" }}>
            <Btn onClick={() => setModal(null)}>Cancel</Btn>
            <Btn variant="primary" onClick={save}>Save</Btn>
          </div>
        </Modal>
      )}
    </div>
  );
}

