/* ─── Toast ───────────────────────────────────────────────────── */
function Toast({ msg, type }) {
  const styles = {
    success: { bg: "#d1fae5", color: "#065f46", border: "#a7f3d0", icon: "✅" },
    danger:  { bg: "#fee2e2", color: "#991b1b", border: "#fca5a5", icon: "⚠️" },
    info:    { bg: `${T.yellow}30`, color: T.dark, border: T.yellow, icon: "ℹ️" },
  };
  const s = styles[type] || styles.success;
  return (
    <div style={{ position: "fixed", bottom: "1.5rem", right: "1.5rem", zIndex: 9999,
      background: s.bg, color: s.color, padding: "0.9rem 1.4rem",
      borderRadius: "var(--border-radius-lg)", border: `1px solid ${s.border}`,
      fontSize: 14, fontWeight: 600, display: "flex", alignItems: "center", gap: 8,
      maxWidth: 380, animation: "slideUp 0.2s ease", boxShadow: "var(--shadow-lg)" }}>
      {s.icon} {msg}
    </div>
  );
}

/* ─── Root ────────────────────────────────────────────────────── */
export default function App() {
  const [users,    setUsers]    = useStorage(USERS_KEY,    defaultUsers);
  const [products, setProducts] = useStorage(PRODUCTS_KEY, defaultProducts);
  const [sales,    setSales]    = useStorage(SALES_KEY,    defaultSales);
  const [settings, setSettings] = useStorage(SETTINGS_KEY, defaultSettings);
  const [session,  setSession]  = useState(null);
  const [page,     setPage]     = useState("dashboard");
  const [toast,    setToast]    = useState(null);

  const showToast = (msg, type = "success") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3500);
  };

  if (!session) return <Login users={users} onLogin={setSession} />;

  return (
    <>
      <style>{`
        @keyframes slideUp { from { transform: translateY(10px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
        input, select {
          background: var(--color-background-primary); color: var(--color-text-primary);
          border: 1.5px solid var(--color-border-secondary); border-radius: var(--border-radius-md);
          padding: 9px 13px; font-size: 14px; outline: none; width: 100%; font-family: var(--font-sans);
          transition: border-color 0.15s, box-shadow 0.15s;
        }
        input:focus, select:focus { border-color: var(--mady-yellow); box-shadow: 0 0 0 3px rgba(255,193,7,0.2); }
        .data-table { border-collapse: collapse; width: 100%; }
        .data-table th, .data-table td { text-align: left; padding: 11px 14px; border-bottom: 1px solid var(--color-border-tertiary); font-size: 14px; }
        .data-table th { font-weight: 700; color: var(--color-text-secondary); font-size: 11px; text-transform: uppercase; letter-spacing: 0.07em; background: var(--color-background-secondary); }
        .data-table tbody tr:last-child td { border-bottom: none; }
        .data-table tbody tr:hover td { background: var(--color-background-secondary); transition: background 0.1s; }
      `}</style>

      <div style={{ display: "flex", minHeight: "100vh", background: "var(--color-background-tertiary)" }}>
        <Sidebar page={page} setPage={setPage} user={session} onLogout={() => { setSession(null); setPage("dashboard"); }} />
        <main style={{ flex: 1, padding: "2rem 2.5rem", overflow: "auto" }}>
          {page === "dashboard" && <Dashboard products={products} sales={sales} setPage={setPage} />}
          {page === "pos"       && <POS products={products} setProducts={setProducts} sales={sales} setSales={setSales} showToast={showToast} settings={settings} />}
          {page === "inventory" && <Inventory products={products} setProducts={setProducts} showToast={showToast} />}
          {page === "history"   && <History sales={sales} setSales={setSales} settings={settings} showToast={showToast} />}
          {page === "report"    && <DailyReport sales={sales} />}
          {page === "users"     && <Users users={users} setUsers={setUsers} session={session} showToast={showToast} />}
          {page === "settings"  && <Settings settings={settings} setSettings={setSettings} showToast={showToast} />}
        </main>
      </div>

      {toast && <Toast {...toast} />}
    </>
  );
}
